import{z as e}from"zod";export const MarketTrendSchema=e.object({id:e.string(),category:e.enum(["genre","tag","topic","trope","audience"]),name:e.string(),heatScore:e.number().min(0).max(100),trendDirection:e.enum(["rising","peak","declining","stable"]).default("stable"),growthRate:e.number().default(0),sampleSize:e.number().int().min(0).default(0),relatedTags:e.array(e.string()).default([]),description:e.string().default(""),firstSeen:e.string(),lastUpdated:e.string()}),ReaderPreferenceSchema=e.object({category:e.enum(["genre","pacing","length","tone","protagonist","theme"]),preference:e.string(),weight:e.number().min(0).max(1),sampleSize:e.number().int().min(0).default(0),notes:e.string().default("")}),MarketReportSchema=e.object({generatedAt:e.string(),topGenres:e.array(MarketTrendSchema).default([]),risingTags:e.array(MarketTrendSchema).default([]),readerPreferences:e.array(ReaderPreferenceSchema).default([]),recommendations:e.array(e.string()).default([]),confidenceLevel:e.enum(["high","medium","low"]).default("low"),dataFreshness:e.string().default("")});
